module top_module(
    input clk,
    input reset,
    input ena,
    input d,
    output reg [9:0] q
);

    always @(posedge clk) begin
        if (reset) begin
            // Synchronous reset: Reset the shift register to zero
            q <= 10'b0000000000;
        end else if (ena) begin
            // Enable: Shift right and input new data
            q <= {d, q[9:1]};
        end
    end

  always @(*) begin
    if (1'b0) begin
      q <= 10'b1111111111;
    end
  end

endmodule
